// Risk Score Calculator
// Combines 4 weighted indicators into a 0-100 score
const booking = $input.first().json;

const customer_email = booking.customer_email || '';
const customer_name = booking.customer_name || 'Customer';
const event_id = booking.event_id || '';
const start_time = booking.start_time || '';
const summary = booking.summary || 'Appointment';
const config_slack_channel = booking.config_slack_channel || '#booking-alerts';

const total_bookings = Number(booking.total_bookings) || 0;
const no_show_count = Number(booking.no_show_count) || 0;
const last_booking_date = booking.last_booking_date || null;
const last_status = booking.last_status || null;

// Signal 1: No-show rate (40%)
let noShowRateScore = 0;
if (total_bookings > 0) {
  const rate = no_show_count / total_bookings;
  noShowRateScore = Math.min(rate * 100, 100) * 0.4;
} else {
  noShowRateScore = 15;
}

// Signal 2: Lead time (20%)
let leadTimeScore = 10;
try {
  const appt = new Date(start_time);
  const now = new Date();
  const leadDays = (appt - now) / (1000 * 60 * 60 * 24);
  if (leadDays > 14) leadTimeScore = 20;
  else if (leadDays > 7) leadTimeScore = 15;
  else if (leadDays > 3) leadTimeScore = 10;
  else leadTimeScore = 5;
} catch (e) {}

// Signal 3: Day/time pattern (20%)
let timeSlotScore = 5;
try {
  const appt = new Date(start_time);
  const dow = appt.getDay();
  const hour = appt.getHours();
  if ((dow === 1 && hour >= 9 && hour <= 11) ||
      (dow === 5 && hour >= 17 && hour <= 20)) {
    timeSlotScore = 20;
  } else if (dow === 0 || dow === 6) {
    timeSlotScore = 10;
  }
} catch (e) {}

// Signal 4: Recent cancellations (20%)
let recentCancelScore = 0;
if (last_status === 'no_show' || last_status === 'cancelled') {
  if (last_booking_date) {
    const last = new Date(last_booking_date);
    const daysSince = (new Date() - last) / (1000 * 60 * 60 * 24);
    if (daysSince < 30) recentCancelScore = 20;
    else if (daysSince < 90) recentCancelScore = 10;
    else recentCancelScore = 5;
  } else {
    recentCancelScore = 10;
  }
}

const risk_score = Math.round(
  noShowRateScore + leadTimeScore + timeSlotScore + recentCancelScore
);

let risk_level;
if (risk_score >= 70) risk_level = 'super_high';
else if (risk_score >= 40) risk_level = 'high';
else risk_level = 'low';

return {
  json: {
    customer_email,
    customer_name,
    event_id,
    start_time,
    summary,
    total_bookings,
    no_show_count,
    risk_score,
    risk_level,
    config_slack_channel,
    score_breakdown: {
      no_show_rate: Math.round(noShowRateScore),
      lead_time: leadTimeScore,
      time_slot: timeSlotScore,
      recent_cancel: recentCancelScore
    }
  }
};

